eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   projects: () => (/* binding */ projects)\n/* harmony export */ });\n// Your projects. The first 3 show on the landing page \"My last works\" section.\n// Each card links to /projects/[slug]. Add as many as you like.\nconst projects = [\n    {\n        slug: \"renesas-h8-300h-pedometer-reverse-engineering\",\n        title: \"Renesas H8/300H Pedometer Reverse Engineering\",\n        short: \"A reverse-engineering project focused on understanding and reproducing the behavior of a Renesas H8/300H-based pedometer system.\",\n        year: \"2026\",\n        tags: [\n            \"Reverse Engineering\",\n            \"Renesas H8/300H\",\n            \"Embedded Systems\"\n        ],\n        description: \"This project focuses on reverse engineering a pedometer built around the Renesas H8/300H architecture. The work involves studying the original firmware and hardware behavior, understanding the embedded system architecture, and using that knowledge to reproduce or reimplement key functionality on modern hardware.\",\n        role: \"Embedded systems and reverse engineering developer\",\n        stack: [\n            \"Renesas H8/300H\",\n            \"Assembly\",\n            \"C\",\n            \"Embedded Systems\",\n            \"Firmware Analysis\"\n        ],\n        live: \"\",\n        repo: \"\",\n        highlights: [\n            \"Analyzed the behavior of a legacy H8/300H-based embedded pedometer\",\n            \"Studied firmware structure, hardware interactions, and low-level system behavior\",\n            \"Connected reverse engineering work with FPGA and embedded system reproduction goals\"\n        ]\n    },\n    {\n        slug: \"fpga-cisc-cpu-system\",\n        title: \"FPGA LR35902-Based CISC CPU Digital System\",\n        short: \"A complete FPGA-based digital system built around an LR35902-inspired CISC CPU, with custom video, audio, HDMI output, SDRAM experiments, and hardware debugging.\",\n        year: \"2025-2026\",\n        tags: [\n            \"FPGA\",\n            \"LR35902\",\n            \"CISC CPU\",\n            \"Verilog\",\n            \"Quartus\",\n            \"Cyclone V\"\n        ],\n        description: \"A complete FPGA-based digital system built around an LR35902-inspired CISC CPU architecture. The CPU is based on the Sharp LR35902 used in the original Game Boy family, combining an 8-bit register-oriented instruction model with memory-mapped I/O, interrupt handling, stack operations, and tight timing requirements. The system also includes an integrated pixel processing unit, audio processing unit, HDMI output, external memory experiments, and hardware-level debugging.\",\n        role: \"FPGA and digital systems developer\",\n        stack: [\n            \"Verilog\",\n            \"VHDL\",\n            \"FPGA\",\n            \"Quartus\",\n            \"Cyclone V\",\n            \"LR35902\",\n            \"CISC CPU\",\n            \"SM83-like CPU\",\n            \"PPU\",\n            \"APU\",\n            \"HDMI\",\n            \"I2S\",\n            \"ADV7513\",\n            \"PLL\",\n            \"LPDDR2 SDRAM\",\n            \"Saleae Logic Analyzer\"\n        ],\n        live: \"\",\n        repo: \"\",\n        highlights: [\n            \"Designed and debugged an LR35902-inspired CISC-style CPU system on FPGA\",\n            \"Implemented custom video and audio processing logic\",\n            \"Integrated HDMI output, PLL clocks, LPDDR2 SDRAM experiments, and Saleae hardware debugging\"\n        ],\n        sections: [\n            {\n                title: \"CPU Architecture\",\n                content: [\n                    {\n                        type: \"paragraph\",\n                        text: \"The core of the project is an LR35902-inspired CISC CPU implemented on FPGA. The LR35902 is the CPU family used in the original Game Boy architecture, and my implementation takes it as the reference point for the register model, instruction behavior, memory-mapped I/O organization, interrupt flow, and timing expectations. The CPU is designed around a classic fetch, decode, and execute flow, with control logic responsible for instruction sequencing, register updates, memory accesses, and flag behavior.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"The architecture includes the main LR35902-style register file, arithmetic and logic operations, program counter control, stack behavior, memory-mapped I/O access, and interrupt-related control paths. A major part of the work was not only implementing the visible behavior of the CPU, but also matching the timing constraints expected by the rest of the system, since the PPU, APU, timers, and memory bus all depend on precise CPU sequencing.\"\n                    },\n                    {\n                        type: \"image\",\n                        src: \"/images/LR35902_schematic.svg\",\n                        alt: \"LR35902 CPU architecture schematic\",\n                        caption: \"LR35902 CPU architecture schematic used as the reference for the FPGA CISC CPU architecture.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"Because the LR35902-style CPU interacts directly with video, audio, memory, and peripheral logic, debugging it required cycle-level observation. Small mistakes in instruction timing, flag updates, interrupt servicing, or memory access order could create bugs much later in the system, especially in the video pipeline or during boot.\"\n                    }\n                ]\n            },\n            {\n                title: \"Instruction Set\",\n                content: [\n                    {\n                        type: \"paragraph\",\n                        text: \"The instruction set follows the LR35902-style programming model, with data transfer instructions, arithmetic operations, logical operations, jumps, calls, returns, stack operations, immediate instructions, register-to-register operations, and memory-addressed instructions.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"A large part of the implementation effort was spent validating how each instruction affects registers, flags, memory, and timing. Instructions that appear simple at first can become difficult when they involve side effects such as flag updates, stack pointer changes, conditional branching, or memory access ordering.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"The project also required testing immediate values, register operands, indirect addressing, and control-flow instructions in a way compatible with LR35902 software expectations. This made the CPU much more than a simple academic processor: it had to behave consistently enough to run real software on top of the FPGA system.\"\n                    }\n                ]\n            },\n            {\n                title: \"Integrated GPU: Pixel Processing Unit\",\n                content: [\n                    {\n                        type: \"paragraph\",\n                        text: \"The system includes an integrated GPU-like module, closer to a Pixel Processing Unit than a modern programmable GPU. Its role is to generate the video output pixel by pixel, using timing-sensitive logic synchronized with the rest of the system.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"The PPU handles background rendering, tile and pixel fetching, scrolling behavior, sprite processing, and video timing. It is responsible for producing the raw pixel stream that later becomes the HDMI image.\"\n                    },\n                    {\n                        type: \"image\",\n                        src: \"/ppu.png\",\n                        label: \"PPU video pipeline placeholder\",\n                        caption: \"Placeholder for a diagram or capture of the pixel pipeline, including background fetching, sprite processing, scroll handling, video timing, and HDMI-facing pixel output.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"One of the main challenges was aligning the PPU timing with memory behavior. Video logic is very sensitive to latency: a one-cycle delay in the wrong place can shift pixels, break scrolling, corrupt sprites, or create visual artifacts. This made the PPU one of the most important debugging targets of the project.\"\n                    }\n                ]\n            },\n            {\n                title: \"Audio Processing Unit\",\n                content: [\n                    {\n                        type: \"paragraph\",\n                        text: \"The Audio Processing Unit generates the digital audio output of the system. It includes timing-sensitive audio channels, sequencing logic, mixing behavior, and output formatting for the HDMI audio path.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"Unlike video bugs, audio bugs are harder to inspect visually. A small synchronization issue can produce distorted, unstable, or inconsistent sound, especially when crossing from internal audio logic to the external HDMI or I2S output path.\"\n                    },\n                    {\n                        type: \"image\",\n                        src: \"/apu.svg\",\n                        label: \"APU signal capture placeholder\",\n                        caption: \"Placeholder for a Saleae capture or waveform showing audio-related signals such as bit clock, word select, serial audio data, or internal sample timing.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"The APU required careful handling of clocks, counters, channel state, sample timing, and reset behavior. One important part of the project was comparing simulation behavior with real FPGA behavior, because audio problems sometimes appeared only after synthesis or after restarting the board.\"\n                    }\n                ]\n            },\n            {\n                title: \"FPGA Integration Process on Quartus\",\n                content: [\n                    {\n                        type: \"paragraph\",\n                        text: \"The design was integrated and synthesized using Intel Quartus for a Cyclone V FPGA board. The FPGA integration process involved connecting the generated CPU, PPU, APU, memory interfaces, HDMI driver, clocks, reset logic, and physical board pins into a single top-level hardware design.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"Quartus integration required working with synthesis reports, timing analysis, pin assignments, resource usage, and generated IP blocks. The project also required debugging issues that only appear after place-and-route, such as timing violations, clock-domain problems, inferred memory behavior, or differences between simulation and real hardware.\"\n                    },\n                    {\n                        type: \"image\",\n                        src: \"/chip.png\",\n                        label: \"Quartus integration placeholder\",\n                        caption: \"Quartus Chip Planner.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"This part of the project was especially important because a design can be logically correct in simulation but still fail on FPGA if the clocks, memories, or I/O paths are not handled correctly.\"\n                    }\n                ]\n            },\n            {\n                title: \"Saleae Logic Analyzer Debugging\",\n                content: [\n                    {\n                        type: \"paragraph\",\n                        text: \"A Saleae logic analyzer was used to debug real hardware signals directly from the FPGA board. This was essential for observing behavior that could not be fully understood from simulation alone.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"For video debugging, the logic analyzer made it possible to inspect pixel clocks, synchronization signals, data enable behavior, and RGB output timing. This helped identify problems such as shifted pixels, unstable video timing, or incorrect signal sequencing.\"\n                    },\n                    {\n                        type: \"image\",\n                        src: \"/video.png\",\n                        label: \"Saleae video signals captured from the FPGA board GPIOs\",\n                        caption: \"Video signals captured from the FPGA board GPIOs\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"For audio debugging, the Saleae was used to inspect I2S-style signals, including bit clock, word select, and serial audio data. This made it possible to compare expected audio timing with the actual signals produced by the FPGA.\"\n                    }\n                ]\n            },\n            {\n                title: \"HDMI Driver\",\n                content: [\n                    {\n                        type: \"paragraph\",\n                        text: \"The HDMI output path is built around an ADV7513 HDMI transmitter. The FPGA generates the video timing, synchronization signals, data enable signal, and RGB pixel data that are sent to the HDMI transmitter.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"The HDMI driver is responsible for converting the internal video output of the system into a format accepted by a standard display. This includes producing stable horizontal and vertical synchronization, a correct pixel clock, and a valid active video region.\"\n                    },\n                    {\n                        type: \"image\",\n                        src: \"/hdmi.png\",\n                        label: \"HDMI output placeholder\",\n                        caption: \"Photo of HDMI output (ROM loading screen)\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"Audio integration also required connecting the APU output to the HDMI path, making the HDMI driver not only a video component but also part of the complete audio and video output system.\"\n                    }\n                ]\n            },\n            {\n                title: \"PLL 25 MHz Clock\",\n                content: [\n                    {\n                        type: \"paragraph\",\n                        text: \"The project uses a 25 MHz pixel clock for the HDMI video pipeline. This clock is required to generate a standard video output timing compatible with the external HDMI transmitter and display.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"The PLL configuration is important because the video output depends on stable and predictable timing. If the pixel clock is unstable, incorrect, or not properly related to the rest of the system, the display output can become corrupted or fail entirely.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"Managing the 25 MHz PLL also introduced clock-domain considerations. The system logic, video pipeline, audio logic, and memory interfaces do not always operate under the same timing constraints, so clean synchronization between domains was necessary.\"\n                    }\n                ]\n            },\n            {\n                title: \"LPDDR2 SDRAM and Its Limits\",\n                content: [\n                    {\n                        type: \"paragraph\",\n                        text: \"LPDDR2 SDRAM was explored as a way to support larger memory requirements than what could fit directly inside FPGA block RAM. This was especially relevant for larger programs, ROM data, or memory regions that exceed the practical limits of internal FPGA memory.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"However, LPDDR2 SDRAM introduces significant complexity. Unlike simple internal memory, SDRAM access has latency, requires a controller, and often runs in a different clock domain from the CPU and video logic.\"\n                    },\n                    {\n                        type: \"image\",\n                        src: \"/memory.svg\",\n                        label: \"LPDDR2 SDRAM architecture placeholder\",\n                        caption: \"Placeholder for a memory architecture diagram showing the CPU, local FPGA memory, LPDDR2 SDRAM controller, ROM loading path, and the timing-sensitive regions that cannot rely directly on external memory latency.\"\n                    },\n                    {\n                        type: \"paragraph\",\n                        text: \"The main limitation is that timing-sensitive CPU or video accesses cannot always wait for unpredictable external memory latency. Some early boot or frequently accessed regions may need to be mirrored into local FPGA memory, cached, or carefully buffered. This made the SDRAM integration useful but not a simple replacement for fast internal memory.\"\n                    }\n                ]\n            }\n        ]\n    },\n    {\n        slug: \"playpal-club\",\n        title: \"PlayPal Club\",\n        short: \"A mobile app for university tennis clubs to organize games, manage players, and build local sports communities.\",\n        year: \"2025\",\n        tags: [\n            \"React Native\",\n            \"Supabase\",\n            \"TypeScript\"\n        ],\n        description: \"PlayPal Club is a social sports app designed for tennis clubs and university communities in Taiwan. It allows users to create games, join matches, manage profiles, track activity, and connect with other players through a mobile-first experience.\",\n        role: \"CTO and full stack developer\",\n        stack: [\n            \"React Native\",\n            \"TypeScript\",\n            \"Supabase\",\n            \"Next.js\",\n            \"Realtime\",\n            \"Push Notifications\"\n        ],\n        live: \"\",\n        repo: \"\",\n        highlights: [\n            \"Built authentication, profiles, game creation, participation, and review flows\",\n            \"Implemented realtime updates and notification logic\",\n            \"Led the technical direction of the project from prototype to mobile deployment preparation\"\n        ]\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///./data/projects.js\n");

